import {
  accodaReview,
  leggiReviewQueue
} from "@italian-oss-legal-platform/backend";
import { NextResponse } from "next/server";

export const runtime = "nodejs";

interface ReviewQueueRequest {
  citazioni?: unknown;
  domanda?: string;
  fontiRecuperate?: unknown;
  metriche?: {
    richiedeRevisioneUmana?: boolean;
  };
  risposta?: string;
}

export async function GET(request: Request) {
  const backendResponse = await proxyBackend("/review/queue", {
    headers: request.headers,
    method: "GET"
  });

  if (backendResponse) {
    return backendResponse;
  }

  const result = await leggiReviewQueue(
    process.env,
    tokenOperatore(request.headers)
  );
  return NextResponse.json(result.body, { status: result.status });
}

export async function POST(request: Request) {
  const rawBody = await request.text();
  const backendResponse = await proxyBackend("/review/queue", {
    body: rawBody,
    headers: request.headers,
    method: "POST"
  });

  if (backendResponse) {
    return backendResponse;
  }

  const result = await accodaReview(parseJson<ReviewQueueRequest>(rawBody));
  return NextResponse.json(result.body, { status: result.status });
}

async function proxyBackend(
  path: string,
  init: { body?: string; headers: Headers; method: "GET" | "POST" }
): Promise<NextResponse | null> {
  const baseUrl = process.env.BACKEND_API_URL?.trim();

  if (!baseUrl) {
    return null;
  }

  const token = tokenOperatore(init.headers);
  const headers: Record<string, string> = {};

  if (init.body) {
    headers["content-type"] = "application/json";
  }

  if (token) {
    headers["x-admin-token"] = token;
  }

  const response = await fetch(`${baseUrl.replace(/\/+$/g, "")}${path}`, {
    body: init.body,
    headers,
    method: init.method
  });

  return NextResponse.json(await response.json(), { status: response.status });
}

function tokenOperatore(headers: Headers): string | undefined {
  const value = headers.get("x-admin-token") ?? headers.get("authorization");
  return value?.replace(/^Bearer\s+/i, "").trim() || undefined;
}

function parseJson<T>(rawBody: string): T | null {
  try {
    return JSON.parse(rawBody) as T;
  } catch {
    return null;
  }
}
